+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import type { RelationPair } from '../../relation/types';
+import type { World } from '../../world';
+import type { EventType, PairTrackingGroup, QueryInstance } from '../types';
+import { checkQueryTracking } from './check-query-tracking';
+
+function matchesPair(filter: RelationPair, pair: RelationPair): boolean {
+    const expected = filter[$internal];
+    const actual = pair[$internal];
+    return (
+        expected.relation === actual.relation &&
+        (expected.target === '*' || expected.target === actual.target)
+    );
+}
+
+function hasEvent(group: PairTrackingGroup, eid: number, pair: RelationPair): boolean {
+    const target = pair[$internal].target;
+    const events = group.events.get(eid);
+    if (!events) return false;
+    if (target !== '*') return events.get(target as number) === group.type;
+    for (const event of events.values()) if (event === group.type) return true;
+    return false;
+}
+
+/** Record a pair event and test all static and tracking constraints. */
+export function checkPairQueryTracking(
+    world: World,
+    query: QueryInstance,
+    entity: Entity,
+    eventType: EventType,
+    pair: RelationPair
+): boolean {
+    const eid = getEntityId(entity);
+    const target = pair[$internal].target;
+    if (typeof target !== 'number') return false;
+
+    for (const group of query.pairTrackingGroups) {
+        let relevant = false;
+        for (const filter of group.pairs) {
+            if (matchesPair(filter, pair)) {
+                relevant = true;
+                break;
+            }
+        }
+        if (!relevant) continue;
+
+        let events = group.events.get(eid);
+        if (!events) group.events.set(eid, (events = new Map()));
+        const previous = events.get(target);
+        // Opposing pair events within the observation window cancel each other.
+        if (previous && previous !== eventType) events.delete(target);
+        else events.set(target, eventType);
+        if (events.size === 0) group.events.delete(eid);
+    }
+
+    // This also verifies static trait constraints and any ordinary tracking groups.
+    if (!checkQueryTracking(world, query, entity, eventType, -1, 0)) return false;
+
+    for (const group of query.pairTrackingGroups) {
+        let matches = group.logic === 'and';
+        for (const filter of group.pairs) {
+            const matched = hasEvent(group, eid, filter);
+            if (group.logic === 'and' && !matched) {
+                matches = false;
+                break;
+            }
+            if (group.logic === 'or' && matched) {
+                matches = true;
+                break;
+            }
+        }
+        if (!matches) return false;
+    }
+    return query.pairTrackingGroups.length > 0;
+}
+
+/** Deliver a pair-level event to queries tracking this relation. */
+export function notifyPairTracking(
+    world: World,
+    entity: Entity,
+    eventType: EventType,
+    pair: RelationPair
+): void {
+    const trait = pair[$internal].relation[$internal].trait;
+    const instance = world[$internal].traitInstances.get(trait);
+    if (!instance) return;
+    for (const query of instance.trackingQueries) {
+        if (query.pairTrackingGroups.length === 0) continue;
+        if (query.checkPairTracking(world, entity, eventType, pair)) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
